package online.yudream.base.interfaces.system.security.assembler;
import online.yudream.base.application.system.security.cmd.ExternalLoginProviderSaveCmd;import online.yudream.base.application.system.security.dto.*;import online.yudream.base.interfaces.system.security.request.ExternalLoginProviderSaveRequest;import online.yudream.base.interfaces.system.security.res.*;
public class ExternalLoginWebAssembler {private ExternalLoginWebAssembler(){} public static ExternalLoginProviderSaveCmd toCmd(ExternalLoginProviderSaveRequest r){ExternalLoginProviderSaveCmd c=new ExternalLoginProviderSaveCmd();c.setCode(r.getCode());c.setName(r.getName());c.setAppId(r.getAppId());c.setAppKey(r.getAppKey());c.setCallbackUrl(r.getCallbackUrl());c.setEnabled(r.isEnabled());c.setSupportedTypes(r.getSupportedTypes());return c;}public static ExternalLoginProviderRes toRes(ExternalLoginProviderDTO d){return ExternalLoginProviderRes.builder().code(d.getCode()).name(d.getName()).protocol(d.getProtocol()).appId(d.getAppId()).callbackUrl(d.getCallbackUrl()).enabled(d.isEnabled()).supportedTypes(d.getSupportedTypes()).build();}public static ExternalLoginAuthorizationRes toRes(ExternalLoginAuthorizationDTO d){return ExternalLoginAuthorizationRes.builder().authorizationUrl(d.getAuthorizationUrl()).state(d.getState()).build();}public static ExternalAccountRes toRes(ExternalAccountDTO d){return ExternalAccountRes.builder().id(d.getId()).providerCode(d.getProviderCode()).platformType(d.getPlatformType()).socialUid(d.getSocialUid()).nickname(d.getNickname()).avatarUrl(d.getAvatarUrl()).createTime(d.getCreateTime()==null?null:d.getCreateTime().toString()).build();}}
